INSERT INTO public.recipe (title,image,"userId",description,"createdAt","updatedAt","deletedAt",categories,ingridients,story) VALUES
	 ('Pasta with Sausage, Basil, and Mustard','recipes-pasta-sausage-basil-and-mustard.webp',1,'<ul><li><p>Gather ingredients.</p></li><li><p>Cook the pasta in a large pot of boiling salted water until al dente and then drain.</p></li><li><p>Meanwhile, heat the olive oil in a large, deep skillet. Add the sausage meat and brown over moderately high heat, about 5 minutes.</p></li><li><p>Add the wine and simmer, scraping up the browned bits from the bottom, until reduced by half, about 5 minutes.</p></li><li><p>Add the cream, mustard, and crushed red pepper and simmer for 2 minutes.</p></li><li><p>Remove the skillet from the heat, add the pasta and basil, and toss to coat.</p></li><li><p>Serve at once.</p></li></ul>','2025-03-07 07:20:42.044',NULL,NULL,'{Pasta}','{"1 pound penne"," rigatoni"," or medium shells","1 tablespoon extra-virgin olive oil","8 hot Italian sausages"," meat removed from casings and crumbled (about 1 1/2 pounds)","3/4 cup dry white wine","3/4 cup heavy cream","3 tablespoons grainy mustard","Pinch of crushed red pepper","1 cup thinly sliced basil"}',NULL);
